// Check which classes are starting within the next 15 minutes
const classes = $input.all().map(item => item.json);
// If response is a single array, unwrap it
const classList = Array.isArray(classes[0]) ? classes[0] : classes;

const now = new Date();
const EST_OFFSET = -5; // EST is UTC-5
const nowEST = new Date(now.getTime() + (now.getTimezoneOffset() + EST_OFFSET * 60) * 60 * 1000);
const currentDay = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'][nowEST.getDay()];
const currentTime = `${String(nowEST.getHours()).padStart(2, '0')}:${String(nowEST.getMinutes()).padStart(2, '0')}`;

const startingSoon = [];

for (const cls of classList) {
  if (!cls.schedule || !cls.zoom_join_url) continue;

  const schedule = typeof cls.schedule === 'string' ? JSON.parse(cls.schedule) : cls.schedule;
  const classDays = schedule.days || [];
  const startTime = schedule.startTime || '';

  if (!classDays.includes(currentDay)) continue;

  // Check if class starts within the next 15 minutes
  const [classHour, classMin] = startTime.split(':').map(Number);
  const classMinutes = classHour * 60 + classMin;
  const nowMinutes = nowEST.getHours() * 60 + nowEST.getMinutes();
  const diff = classMinutes - nowMinutes;

  if (diff >= 0 && diff <= 15) {
    startingSoon.push({
      json: {
        class_id: cls.id,
        class_name: cls.name,
        zoom_join_url: cls.zoom_join_url,
        zoom_start_url: cls.zoom_start_url,
        zoom_meeting_id: cls.zoom_meeting_id,
        instructor_id: cls.instructor_id,
        start_time: startTime,
        current_day: currentDay,
        minutes_until_start: diff
      }
    });
  }
}

if (startingSoon.length === 0) {
  return [{ json: { no_classes: true } }];
}

return startingSoon;

// Create in-portal messages for each enrolled student
const classData = $('Has Classes Starting').item.json;
const enrollments = $input.all().map(item => item.json);
// Handle both array and single-item response
const studentIds = Array.isArray(enrollments[0]) 
  ? enrollments[0].map(e => e.student_id) 
  : enrollments.map(e => e.student_id);

const messages = studentIds.map(studentId => ({
  tenant_id: '00000000-0000-0000-0000-000000000001',
  sender_id: classData.instructor_id,
  recipient_id: studentId,
  subject: `Class Starting: ${classData.class_name}`,
  body: `Your class "${classData.class_name}" is starting ${classData.minutes_until_start === 0 ? 'now' : `in ${classData.minutes_until_start} minutes`}.\n\nJoin via Zoom: ${classData.zoom_join_url}`,
  message_type: 'class_reminder',
  is_system: true,
  is_read: false
}));

return [{ json: { messages, student_count: studentIds.length, class_name: classData.class_name } }];

